import{_ as a,o as t,c as s,a4 as i}from"./chunks/framework.PZCYvDoh.js";const o="/XIAOHUANG_BLOG/assets/image-20260529132014780.Co_aFpPn.png",l="/XIAOHUANG_BLOG/assets/image-20260529141241453.BEpSSr_k.png",r="/XIAOHUANG_BLOG/assets/afd872c4b0db76d40fe811695283262c.De23oehH.png",n="/XIAOHUANG_BLOG/assets/image-20260629123456575.BeuKNNnn.png",p="/XIAOHUANG_BLOG/assets/image-20260605141720182.Doez8jR4.png",c="/XIAOHUANG_BLOG/assets/image-20260602160952749.ZDWVQ6nl.png",m="/XIAOHUANG_BLOG/assets/image-20260627200800977.DD_MlAai.png",d="/XIAOHUANG_BLOG/assets/image-20260606162454352.TAhG-FCM.png",u="/XIAOHUANG_BLOG/assets/image-20260523221025896.2ekyfWeI.png",v=JSON.parse('{"title":"PX4 Simulink教程","description":"","frontmatter":{},"headers":[],"relativePath":"docs/硬件资料/旋翼无人机/px4_Simulink教程/PX4_Simulink教程.md","filePath":"docs/硬件资料/旋翼无人机/px4_Simulink教程/PX4_Simulink教程.md"}'),h={name:"docs/硬件资料/旋翼无人机/px4_Simulink教程/PX4_Simulink教程.md"};function g(k,e,_,b,f,x){return t(),s("div",null,[...e[0]||(e[0]=[i(`<h1 id="px4-simulink教程" tabindex="-1">PX4 Simulink教程 <a class="header-anchor" href="#px4-simulink教程" aria-label="Permalink to &quot;PX4 Simulink教程&quot;">​</a></h1><p>官方教程链接：<a href="https://ww2.mathworks.cn/help/uav/px4-spkg.html" target="_blank" rel="noreferrer">UAV Toolbox Support Package for PX4 Autopilots - MATLAB &amp; Simulink</a> 官方视频链接：<a href="https://www.bilibili.com/video/BV1P94y1D7cu/?vd_source=369d383c90729d8c8b513367020c1468" target="_blank" rel="noreferrer">自主系统 | 基于 SIL 和 HIL 工作流仿真并部署无人机应用_哔哩哔哩_bilibili</a></p><p>matlab online:<a href="https://matlab.mathworks.com/" target="_blank" rel="noreferrer">MATLAB</a></p><p>硬件在环教程：<a href="https://ww2.mathworks.cn/help/uav/px4/ref/hitl-simulink-plant-example.html" target="_blank" rel="noreferrer">在Simulink - MATLAB和Simulink中，利用无人机动力学在硬件环路（HITL）模拟中运行PX4自动驾驶仪</a></p><div class="tip custom-block github-alert"><p class="custom-block-title">TIP</p><p></p><p>**问题1：**我是px4和simulink联合开发控制器的，但是通过simulink烧录固件后就无法通过usb使用QGC了，我想先用usb通过QGC进行机体校准，校准完后再用usb链接simulink开发控制器，应该怎么操作怎么设置参数？</p><p>**方案1：**开启两个slx，一个存放控制器，通过Run on board的监控并调节运行（pc通过usb口连接到px4，运行控制器），另一个slx存放被控对象，通过仿真-运行运行simulink中的由solidworks+urdf导出的无人机模型，然后通过MAVLink Bridge Source获取四个电机的actuator数据，然后通过MAVLink Bridge Sink下发传感器数据（pc通过如GPS的串口连接到px4），其中，<strong>QGC 已经占用了 TELEM1 端口（通过数传电台），而你的 Simulink “Monitor &amp; Tune” 专用通道会使用另外一个串口（例如 GPS 串口或其他空闲串口）</strong></p></div><div class="tip custom-block github-alert"><p class="custom-block-title">TIP</p><p></p><p>注意点</p><p>1、不要轻易重烧固件</p><p>2、每次重烧固件后都要做电调校准</p><p>3、使用simulink连接的时候一定要先插usb，再插电池，否则就会要求重新烧录（禁止）</p></div><h2 id="固件下载" tabindex="-1">固件下载 <a class="header-anchor" href="#固件下载" aria-label="Permalink to &quot;固件下载&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>git clone https://github.com/PX4/PX4-Autopilot.git</span></span>
<span class="line"><span>mv PX4-Autopilot PX4_Firmware  # 更改目录名</span></span>
<span class="line"><span>cd PX4_Firmware</span></span>
<span class="line"><span>git checkout v1.15.4</span></span>
<span class="line"><span>git submodule update --init --recursive --force</span></span>
<span class="line"><span>make px4_sitl_default  #编译 SITL 仿真固件</span></span></code></pre></div><h2 id="pixhawk4板载资源" tabindex="-1">Pixhawk4板载资源 <a class="header-anchor" href="#pixhawk4板载资源" aria-label="Permalink to &quot;Pixhawk4板载资源&quot;">​</a></h2><p>官方中文：<a href="https://docs.ncnynl.com/en/px4/zh/assembly/quick_start_pixhawk4.html" target="_blank" rel="noreferrer">Pixhawk 4 接线快速入门 | PX4 Guide (main)</a></p><p>[如何系统上手 Pixhawk 4：基于Holybro官方资料的接线与入门教学_holybro官网-CSDN博客](<a href="https://blog.csdn.net/2402_87963769/article/details/160418650?ops_request_misc=&amp;request_id=&amp;biz_id=102&amp;utm_term=pixhawk4" target="_blank" rel="noreferrer">https://blog.csdn.net/2402_87963769/article/details/160418650?ops_request_misc=&amp;request_id=&amp;biz_id=102&amp;utm_term=pixhawk4</a> 原理图&amp;utm_medium=distribute.pc_search_result.none-task-blog-2~all~sobaiduweb~default-0-160418650.142^v102^pc_search_result_base7&amp;spm=1018.2226.3001.4187)</p><p>引脚图，FMUv5参考设计引脚： <a href="PX4_Simulink%E6%95%99%E7%A8%8B.assets%5CPixhawk4-Pinouts.pdf">Pixhawk4-Pinouts.pdf</a></p><p>串口映射：<a href="https://docs.px4.io/main/zh/flight_controller/pixhawk4#%E4%B8%B2%E5%8F%A3%E6%98%A0%E5%B0%84" target="_blank" rel="noreferrer">霍利布罗小鹰4 |PX4 指南（主）</a></p><img src="`+o+'" alt="image-20260529132014780" style="zoom:33%;"><p>Telem1、Telem2</p><img src="'+l+'" alt="image-20260529141241453" style="zoom:50%;"><h3 id="串口" tabindex="-1">串口 <a class="header-anchor" href="#串口" aria-label="Permalink to &quot;串口&quot;">​</a></h3><img src="'+r+'" alt="afd872c4b0db76d40fe811695283262c" style="zoom:25%;"><h3 id="elrs遥控教程" tabindex="-1">ELRS遥控教程 <a class="header-anchor" href="#elrs遥控教程" aria-label="Permalink to &quot;ELRS遥控教程&quot;">​</a></h3><p>修改以适配ELRS接收机教程：<a href="https://www.cnblogs.com/vokaol/p/20141454" target="_blank" rel="noreferrer"># PX4ELRS接收机的设置 - vokaol - 博客园</a></p><p>官方教程：<a href="https://docs.px4.io/main/zh/telemetry/crsf_telemetry" target="_blank" rel="noreferrer">CRSF Telemetry (TBS Crossfire Telemetry) | PX4 Guide (main)</a></p><img src="'+n+'" alt="image-20260629123456575" style="zoom:67%;"><div class="tip custom-block github-alert"><p class="custom-block-title">TIP</p><p></p><p>配置方法：由于PX4固件<strong>默认不包含</strong>对ELRS所用CRSF协议的支持，必须手动编译一个定制的固件。</p><ol><li><strong>启动配置工具</strong>：进入PX4源码目录，执行 <code>make px4_fmu-v5_multicopter boardconfig</code> （或者<code>make px4_fmu-v5_default boardconfig</code>）进入图形化配置界面。</li><li><strong>禁用通用RC输入</strong>：找到路径 <code>drivers</code> → <code>rc_input</code>，按<code>N</code>或<code>Enter</code>键取消其前方的 <code>[*]</code> 标记，变为 <code>[ ]</code>。</li><li><strong>启用CRSF驱动</strong>：找到路径 <code>drivers</code> → <code>RC</code> → <code>crsf_rc</code>，按<code>Y</code>或<code>Enter</code>键<strong>选中它</strong>，使其前方出现星号 <code>[*]</code>。</li><li><strong>保存并编译</strong>：按<code>S</code>保存配置，退出后执行 <code>make px4_fmu-v5_multicopter</code>（或者<code>make px4_fmu-v5_default</code>） 开始编译。</li></ol><p><strong>QGC参数配置</strong></p><p>将生成的固件通过QGC烧录进飞控，重启后在 <strong>参数 (Parameters)</strong> 界面搜索并修改：</p><ul><li><strong><code>RC_CRSF_PRT_CFG</code></strong>：设置为 <code>TELEM4</code> (或你实际连接ELRS接收机的串口号)。</li></ul><div class="caution custom-block github-alert"><p class="custom-block-title">CAUTION</p><p></p><p>禁止设置<strong>MAV_0_CONFIG</strong>不使用</p><p>一不小心修改后的解决方法：使用低版本固件烧录修改该参数再重新烧录当前版本</p><p>pix4v1143: <a href="./PX4_Simulink教程.assets\\固件\\soft1143\\px4_fmu-v5_default.px4.html">px4_fmu-v5_default.px4</a></p><p>pix4v1140: <a href="./PX4_Simulink教程.assets\\固件\\soft1140\\px4_fmu-v5_default.px4.html">px4_fmu-v5_default.px4</a></p></div></div><h3 id="电源" tabindex="-1">电源 <a class="header-anchor" href="#电源" aria-label="Permalink to &quot;电源&quot;">​</a></h3><img src="'+p+'" alt="image-20260605141720182" style="zoom:50%;"><h3 id="电机" tabindex="-1"><strong>电机</strong> <a class="header-anchor" href="#电机" aria-label="Permalink to &quot;**电机**&quot;">​</a></h3><p>电压安全输入：</p><p>POWER1和POWER2输入（工作范围4.1V至5.7V，0V至10V无损）</p><p>USB输入（工作范围4.1V至5.7V，0V至6V无损）</p><p>伺服输入：VDD_SERVO脚的FMU PWM输出和I/O PWM输出（0V到42V未损坏）</p><p>I/O PWM OUT：由独立的I/O协处理器（STM32F100）管理</p><p>FMU PWM OUT：由直接由主FMU处理器（STM32F765）控制</p><img src="'+c+'" alt="image-20260602160952749" style="zoom:50%;"><p>电机顺序与方向调整</p><img src="'+m+'" alt="image-20260627200800977" style="zoom:67%;"><h3 id="光流计" tabindex="-1">光流计 <a class="header-anchor" href="#光流计" aria-label="Permalink to &quot;光流计&quot;">​</a></h3><p>参考：<a href="https://micoair.cn/docs/MTF01-guang-liu-ce-ju-yi-ti-chuan-gan-qi-yong-hu-shou-ce" target="_blank" rel="noreferrer">MTF-01光流测距一体传感器-用户手册-微空科技</a></p><h3 id="报错解决" tabindex="-1">报错解决 <a class="header-anchor" href="#报错解决" aria-label="Permalink to &quot;报错解决&quot;">​</a></h3><div class="caution custom-block github-alert"><p class="custom-block-title">CAUTION</p><p></p><p><strong>The value of the &#39;MaxStackSize&#39; parameter is forcing a local variable to be global in the generated code. Since &#39;EnableMultiTasking&#39; is on, this global variable may be unpredictably read from and written to on more than one task. To fix this error, either specify a higher &#39;MaxStackSize&#39; or turn off &#39;EnableMultiTasking&#39;. 组件:Simulink | 类别:Model 错误</strong></p><div class="tip custom-block github-alert"><p class="custom-block-title">TIP</p><p></p><ol><li>在 Simulink 模型界面，按 <code>Ctrl+E</code> 打开 <strong>模型配置参数 (Model Configuration Parameters)</strong>。</li><li>左侧导航栏选择 <strong>代码生成 (Code Generation)</strong> → <strong>优化 (Optimization)</strong>。</li><li>找到 <strong>最大堆栈大小(字节) (Maximum stack size (bytes))</strong> 参数。 <ul><li>默认可能是 <code>Inherit from target</code> 或一个较小的数值（如 <code>200000</code>）。</li><li><strong>将其改为</strong>：<code>Specify a value</code>，然后在输入框中填入 <strong><code>2000000</code></strong> （两百万字节，约 2 MB）。</li><li>Pixhawk 4 的总 RAM 为 2 MB，但你的模型通常不会独占全部内存。这个数值给栈分配了足够空间，且仍在安全范围内。</li></ul></li><li>点击 <strong>应用 (Apply)</strong> → <strong>确定 (OK)</strong>。</li><li>重新启动编译（点击 Monitor &amp; Tune 或按 <code>Ctrl+B</code>）。</li></ol></div></div><div class="caution custom-block github-alert"><p class="custom-block-title">CAUTION</p><p></p><p><strong>错误:第一个输入必须为字符串数组或字符向量元胞数组。</strong></p><div class="tip custom-block github-alert"><p class="custom-block-title">TIP</p><p></p><p><strong>MATLAB 项目或生成代码的路径中包含了中文字符（例如 <code>H:\\大学期间各项资料...</code>）</strong></p><p>并删除先前的构建残留文件后重新构建</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>rm -rf /home/xiaohuang_tongxue/px4simulink_1154/PX4-Autopilot/src/modules/px4_simulink_app</span></span></code></pre></div><p><strong>注意在simulink中px4配置的时候，路径要设置为</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/home/xiaohuang_tongxue/px4simulink_1154/PX4-Autopilot</span></span></code></pre></div><p><strong>不允许使用以下内容</strong></p><img src="'+d+'" alt="image-20260606162454352" style="zoom:50%;"></div></div><h2 id="matlab例程介绍" tabindex="-1">Matlab例程介绍 <a class="header-anchor" href="#matlab例程介绍" aria-label="Permalink to &quot;Matlab例程介绍&quot;">​</a></h2><div class="language-matlab vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">matlab</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">openExample(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;px4/PositionTrackingControllerTypeQuadrotorVehicleExample&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span></code></pre></div><img src="'+u+'" alt="image-20260523221025896" style="zoom:67%;"><p>先看这个：<a href="https://ww2.mathworks.cn/help/uav/px4/ug/deployment-using-px4hosttarget-jmavsim.html" target="_blank" rel="noreferrer">使用 PX4 主机目标和 jMAVSim/Simulink 的部署与验证 - MATLAB 和 Simulink</a></p><p>主要参考（软件在环教程）：<a href="https://ww2.mathworks.cn/help/uav/px4/ref/simulator-plant-model-example.html" target="_blank" rel="noreferrer">在Simulink - MATLAB和Simulink中运行PX4软件环路仿真，配合四旋翼机设备</a></p><p>软件在环的工程路径：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>C:\\Users\\86153\\Documents\\MATLAB\\Examples\\R2026a\\px4\\RunPX4SITLWithQuadcopterPlantExample\\Px4DemoHostTargetWithSimulinkPlant</span></span></code></pre></div>',47)])])}const S=a(h,[["render",g]]);export{v as __pageData,S as default};
